def test_reconciliation_zero_variance_report_stored():
    import requests
    import json
    from datetime import datetime

    payload = {
        "internal_balance": 1000000.00,
        "bank_balance": 1000000.00,
        "currency": "USD"
    }

    resp = requests.post(
        "http://localhost:8080/cron/reconcile",
        json=payload,
        headers={"Authorization": "Bearer <valid_token>"}
    )

    assert resp.status_code == 200
    data = resp.json()
    reconciliation_id = data["reconciliation_id"]

    report = requests.get(
        f"http://localhost:8080/reports/{reconciliation_id}",
        headers={"Authorization": "Bearer <valid_token>"}
    ).json()

    assert report["variance"] == 0.0
    assert report["incident_opened"] is False

