def test_reconciliation_bank_service_unavailable():
    import requests
    from requests.exceptions import ConnectionError, Timeout

    payload = {
        "internal_balance": 1000000.00,
        "bank_balance": 1000000.00,
        "currency": "USD"
    }

    try:
        resp = requests.post(
            "http://localhost:8080/cron/reconcile",
            json=payload,
            headers={"Authorization": "Bearer <valid_token>"},
            timeout=5
        )
        assert resp.status_code in [503, 504, 500]
    except (ConnectionError, Timeout):
        assert True

